import java.util.*;class A{static int W,H,cx,cy,px,py,sc;static boolean ref;static List<int[]>C=new ArrayList<>(),hist=new ArrayList<>();static List<int[]>filt(List<int[]>c,int px,int py,int cx,int cy,int h,int s){var r=new ArrayList<int[]>();for(var p:c){long dp=(long)(p[0]-px)*(p[0]-px)+(long)(p[1]-py)*(p[1]-py);long dc=(long)(p[0]-cx)*(p[0]-cx)+(long)(p[1]-cy)*(p[1]-cy);if(h==0&&dc<dp||h==1&&dc>dp||h==2&&(s>1||dc==dp))r.add(p);}return r;}public static void main(String[]args){var s=new Scanner(System.in);W=s.nextInt();H=s.nextInt();s.nextInt();cx=s.nextInt();cy=s.nextInt();sc=1;while((long)((W+sc-1)/sc)*((H+sc-1)/sc)>62500)sc*=2;for(int y=0;y<H;y+=sc)for(int x=0;x<W;x+=sc)C.add(new int[]{Math.min(x+sc/2,W-1),Math.min(y+sc/2,H-1)});px=cx;py=cy;ref=sc==1;for(;;){var h=s.next();int hi=h.charAt(0)=='W'?0:h.charAt(0)=='C'?1:2;if(h.equals("WARMER")||h.equals("COLDER")||h.equals("SAME")){hist.add(new int[]{px,py,cx,cy,hi});C=filt(C,px,py,cx,cy,hi,sc);if(!ref&&C.size()<=3){var seen=new HashSet<Long>();var exp=new ArrayList<int[]>();for(var p:C)for(int ny=p[1]-sc;ny<=p[1]+sc;ny++)for(int nx=p[0]-sc;nx<=p[0]+sc;nx++){int px2=Math.max(0,Math.min(W-1,nx)),py2=Math.max(0,Math.min(H-1,ny));long k=(long)py2*W+px2;if(seen.add(k))exp.add(new int[]{px2,py2});}for(var hh:hist)exp=filt(exp,hh[0],hh[1],hh[2],hh[3],hh[4],1);C=exp;sc=1;ref=true;}}px=cx;py=cy;if(C.size()<=1){if(C.size()==1){cx=C.get(0)[0];cy=C.get(0)[1];}}else if(C.size()<=80){int best=Integer.MAX_VALUE,bx=cx,by=cy;for(var p:C){if(p[0]==cx&&p[1]==cy)continue;int w=0,c2=0;for(var a:C){long dp=(long)(a[0]-cx)*(a[0]-cx)+(long)(a[1]-cy)*(a[1]-cy);long dt=(long)(a[0]-p[0])*(a[0]-p[0])+(long)(a[1]-p[1])*(a[1]-p[1]);if(dt<dp)w++;else if(dt>dp)c2++;}int sc2=Math.abs(w-c2);if(sc2<best){best=sc2;bx=p[0];by=p[1];}}cx=bx;cy=by;}else{long sx=0,sy=0;for(var p:C){sx+=p[0];sy+=p[1];}cx=(int)Math.round((double)sx/C.size());cy=(int)Math.round((double)sy/C.size());}if(cx==px&&cy==py&&!C.isEmpty()){long md=-1;for(var p:C){long d=(long)(p[0]-cx)*(p[0]-cx)+(long)(p[1]-cy)*(p[1]-cy);if(d>md){md=d;cx=p[0];cy=p[1];}}}System.out.println(cx+" "+cy);System.out.flush();}}}